class Sample {
private:
 int x, y;
public:
 void setData(int x, int y) {
 // Without this: parameter shadows member
 // With this: clearly refers to member variables
 this->x = x;
 this->y = y;
 }
 void display() {
 cout << "x: " << this->x << endl;
 cout << "y: " << this->y << endl;
 }
};

int main() {
 Sample obj;
 obj.setData(10, 20);
 obj.display();
 return 0;
}

class Calculator {
private:
 int a, b, c;
public:
 Calculator& setA(int val) {
 this->a = val;
 return *this; // Return current object
 }
 Calculator& setB(int val) {
 this->b = val;
 return *this;
 }
 Calculator& setC(int val) {
 this->c = val;
 return *this;
 }
 void display() {
 cout << a << ", " << b << ", " << c << endl;
 }
};

int main() {
 Calculator calc;
 // Function chaining - each method returns *this
 calc.setA(10).setB(20).setC(30).display();
 return 0;
}

class Complex {
private:
 float real, imag;
public:
 Complex(float r = 0, float i = 0) : real(r), imag(i) {}

 // Binary operator + as member function
 Complex operator+(const Complex& c) {
 return Complex(real + c.real, imag + c.imag);
 }

 // Compound assignment += using this
 Complex& operator+=(const Complex& c) {
 // this points to left operand (obj1)
 this->real += c.real;
 this->imag += c.imag;
 return *this; // Return modified object
 }

 void display() {
 cout << real << " + " << imag << "i" << endl;
 }
};

int main() {
 Complex c1(3, 4), c2(1, 2), c3;

 c3 = c1 + c2; // Uses operator+
 c1 += c2; // Uses operator+= (this = &c1)

 c1.display();
 c3.display();
 return 0;
}

class Demo {
private:
 int value;
public:
 Demo(int v = 0) : value(v) {}

 // Non-const member function
 void modify() {
 // this is: Demo *const (can modify)
 this->value = 100;
 // this = nullptr; // ERROR: cannot modify this
 }

 // Const member function
 void show() const {
 // this is: const Demo *const (cannot modify)
 cout << "Value: " << this->value << endl;
 // this->value = 50; // ERROR: cannot modify through const this
 }

 // Static function - NO this pointer
 static void staticMethod() {
 // this is NOT available here
 // Demo::value; // ERROR: cannot access non-static member
 }
};

int main() {
 Demo obj(50);
 obj.modify(); // Can modify
 obj.show(); // Read-only access
 Demo::staticMethod(); // No object needed
 return 0;
}
